// PII scrubber (espelho de backend/app/services/pii.py)
// Bloqueia fluxo se PII detectado -> handoff humano LGPD art. 7 I.
const items = $input.all();
const out = [];
const patterns = [
  { label: 'email',    re: /\b[\w.+-]+@[\w-]+\.[\w.-]+\b/g },
  { label: 'data',     re: /\b\d{2}[\/\-\.]\d{2}[\/\-\.]\d{4}\b|\b\d{4}-\d{2}-\d{2}\b/g },
  { label: 'placa_veiculo',    re: /\b[A-Z]{3}-?\d[A-Z]\d{2}\b|\b[A-Z]{3}-?\d{4}\b/g },
  { label: 'cnpj',     re: /\b\d{2}\.?\d{3}\.\d{3}\/\d{4}-?\d{2}\b/g },
  { label: 'cpf',      re: /\b\d{3}\.\d{3}\.\d{3}-?\d{2}\b/g },
  { label: 'pis',      re: /\b\d{3}\.\d{5}\.\d{3}\b/g },
  { label: 'rg',       re: /\b\d{1,2}\.\d{3}\.?\d{3}-?[\dxX]\b/g },
  { label: 'titulo',   re: /\b\d{4}\s?\d{4}\s?\d{4}\b/g },
  { label: 'phone_br', re: /(?:\+?55\s?)?\(?\d{2}\)?\s?9?\d{4}[\s-]?\d{4}/g },
  { label: 'cep',      re: /\b\d{5}-?\d{3}\b/g },
  { label: 'cartao',   re: /\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b|\b\d{4}[\s-]?\d{6}[\s-]?\d{5}\b/g }
];
for (const item of items) {
  const raw = (item.json.raw_text || '').toString();
  let scrubbed = raw;
  const findings = {};
  let cnt = 0;
  for (const p of patterns) {
    const m = scrubbed.match(p.re);
    if (m && m.length) {
      findings[p.label] = m.length;
      cnt += m.length;
      scrubbed = scrubbed.replace(p.re, '[' + p.label.toUpperCase() + '_REDACTED]');
    }
  }
  const blocked = cnt > 0;
  out.push({
    json: {
      sender: item.json.sender || 'unknown',
      instance: item.json.instance || 'cartorio-2notas-uberlandia',
      canal: item.json.canal || 'whatsapp',
      scrubbed: scrubbed,
      findings: findings,
      redaction_count: cnt,
      blocked: blocked,
      consent_granted: !blocked,
      timestamp: new Date().toISOString()
    }
  });
}
return out;

// Decide response: PII blocked -> handoff. Else MCP tool result.
const items = $input.all();
const out = [];
for (const item of items) {
  const scrub = $('PII Scrubber').item.json;
  const mcp = item.json || {};
  const isPii = scrub && scrub.redaction_count > 0;
  let r;
  if (isPii) {
    r = {
      status: 'pii_blocked',
      response: 'Detectei dados pessoais (CPF/RG/documento). Por questao de LGPD, vou transferir seu atendimento para um escrevente humano. Aguarde.',
      sender: scrub.sender || 'unknown',
      pii_blocked: true,
      pii_redaction_count: scrub.redaction_count || 0,
      needs_human_handoff: true,
      model: null,
      tokens_in: null,
      tokens_out: null,
      latency_ms: null,
      provider: 'handoff_humano',
      transport: 'mcp'
    };
  } else {
    // MCP tool result pode vir em result.content[0].text (JSON string) ou direto
    const toolResult = mcp.result || mcp;
    const responseText = toolResult.response || (toolResult.content && toolResult.content[0] && toolResult.content[0].text) || null;
    const ok = toolResult.status === 'ok' && responseText;
    r = {
      status: ok ? 'ok' : 'llm_error',
      response: ok ? responseText : 'Desculpe, nao consegui processar sua mensagem. Um atendente humano ira retornar.',
      sender: scrub.sender || 'unknown',
      pii_blocked: false,
      pii_redaction_count: 0,
      needs_human_handoff: !ok,
      model: toolResult.model || 'deepseek-v4-flash',
      tokens_in: toolResult.tokens_in || null,
      tokens_out: toolResult.tokens_out || null,
      latency_ms: toolResult.latency_ms || null,
      provider: toolResult.provider || 'opencode_go',
      transport: 'mcp'
    };
  }
  out.push({ json: r });
}
return out;
